import { useCallback, useEffect, useMemo, useState } from "react";
import { normalizeError, resolvePodClient } from "./utils.js";
export function useAgentInputSchema({ client, podId, agentName, enabled = true, autoLoad = true, }) {
    const [agent, setAgent] = useState(null);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState(null);
    const trimmedAgentName = agentName.trim();
    const isEnabled = enabled && trimmedAgentName.length > 0;
    const refresh = useCallback(async (signal) => {
        if (!isEnabled) {
            setAgent(null);
            setError(null);
            setIsLoading(false);
            return null;
        }
        setIsLoading(true);
        setError(null);
        try {
            const scopedClient = resolvePodClient(client, podId);
            const nextAgent = await scopedClient.agents.get(trimmedAgentName);
            if (signal?.aborted)
                return null;
            setAgent(nextAgent);
            return nextAgent;
        }
        catch (refreshError) {
            if (signal?.aborted)
                return null;
            const normalized = normalizeError(refreshError, "Failed to load agent schema.");
            setError(normalized);
            setAgent(null);
            return null;
        }
        finally {
            if (!signal?.aborted)
                setIsLoading(false);
        }
    }, [client, isEnabled, podId, trimmedAgentName]);
    useEffect(() => {
        if (!isEnabled) {
            setAgent(null);
            setError(null);
            setIsLoading(false);
            return;
        }
        if (!autoLoad)
            return;
        const controller = new AbortController();
        let cancelled = false;
        (async () => {
            try {
                await refresh(controller.signal);
            }
            catch {
                if (!cancelled) {
                    setError(normalizeError(new Error("Failed to load agent schema."), "Failed to load agent schema."));
                }
            }
        })();
        return () => {
            cancelled = true;
            controller.abort();
        };
    }, [autoLoad, isEnabled, refresh]);
    return useMemo(() => ({
        agent,
        inputSchema: (agent?.input_schema ?? null),
        outputSchema: (agent?.output_schema ?? null),
        isLoading,
        error,
        refresh,
    }), [agent, error, isLoading, refresh]);
}
